// SHA-256 implementado em JS puro — sem dependências
function sha256(str) {
  function rightRotate(value, amount) {
    return (value >>> amount) | (value << (32 - amount));
  }
  const mathPow = Math.pow;
  const maxWord = mathPow(2, 32);
  let result = '';
  const words = [];
  const asciiBitLength = str.length * 8;
  let hash = [];
  let k = [];
  let primeCounter = 0;
  const isComposite = {};
  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (let i = candidate * candidate; i < 313; i += candidate) isComposite[i] = true;
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1 / 3) * maxWord) | 0;
    }
  }
  str += '\x80';
  while (str.length % 64 - 56) str += '\x00';
  for (let i = 0; i < str.length; i++) {
    const j = str.charCodeAt(i);
    if (j >> 8) return '';
    words[i >> 2] |= j << ((3 - i) % 4) * 8;
  }
  words[words.length] = (asciiBitLength / maxWord) | 0;
  words[words.length] = asciiBitLength;
  for (let j = 0; j < words.length;) {
    const w = words.slice(j, (j += 16));
    const oldHash = hash.slice(0);
    for (let i = 0; i < 64; i++) {
      const i2 = i + j - 16;
      const w15 = w[i - 15], w2 = w[i - 2];
      const a = hash[0], e = hash[4];
      const temp1 = hash[7] +
        (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25)) +
        ((e & hash[5]) ^ (~e & hash[6])) + k[i] +
        (w[i] = i < 16 ? w[i] : (
          w[i - 16] +
          (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3)) +
          w[i - 7] +
          (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))
        ) | 0);
      const temp2 =
        (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22)) +
        ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.length = 8;
    }
    hash = hash.map((a, i) => (a + oldHash[i]) | 0);
  }
  for (let i = 0; i < 8; i++) {
    for (let j = 3; j + 1; j--) {
      const b = (hash[i] >> (j * 8)) & 255;
      result += (b < 16 ? '0' : '') + b.toString(16);
    }
  }
  return result;
}

const prep = $('Preparar dados1').first().json;
const cfg = $('⚙️ CONFIG1').first().json;
let session = $('Buscar sessão por telefone').first().json;
if (Array.isArray(session)) session = session[0];

const phoneHash = sha256(String(prep.phone).toLowerCase());
const eventTime = Math.floor(Date.now() / 1000);

const baseUserData = {
  ph: [phoneHash],
  fbc: session.fbc || undefined,
  fbp: session.fbp || undefined,
};

const items = [];

if (prep.hasTagLead) {
  items.push({
    json: {
      payload: {
        data: [{
          event_name: 'Lead',
          event_time: eventTime,
          action_source: 'website',
          user_data: baseUserData,
        }],
        test_event_code: cfg.test_event_code,
      },
      pixel_id: cfg.meta_pixel_id,
      access_token: cfg.meta_access_token,
    },
  });
}

if (prep.hasTagCompra) {
  const v = parseFloat(prep.valor);
  const value = Number.isFinite(v) ? v : 0;
  items.push({
    json: {
      payload: {
        data: [{
          event_name: 'Purchase',
          event_time: eventTime,
          action_source: 'website',
          user_data: baseUserData,
          custom_data: {
            value: value,
            currency: 'BRL',
          },
        }],
        test_event_code: cfg.test_event_code,
      },
      pixel_id: cfg.meta_pixel_id,
      access_token: cfg.meta_access_token,
    },
  });
}

return items;

